function solve(nums: number[]): number {
    let count = 0; // Represents the required value (and target index j) for the next fixed point
    let startIndex = 0;
    const N = nums.length;

    while (startIndex < N) {
        let found = false;
        let bestIndex = -1;

        // Search for the smallest index i >= startIndex such that nums[i] == count
        // This greedy choice ensures we leave the maximum possible space for future matches.
        for (let i = startIndex; i < N; i++) {
            if (nums[i] === count) {
                bestIndex = i;
                found = true;
                break; 
            }
        }

        if (found) {
            // Successfully found an element that can become a fixed point at index 'count'
            count++;
            // Start search for the next element (target count + 1) from the index immediately following the found element
            startIndex = bestIndex + 1;
        } else {
            // Cannot find the required element for the current target count
            break;
        }
    }

    return count;
}
